DECLARE
  v_dob DATE;
  v_str VARCHAR2(100) := TRIM(:p_date_of_birth);
  v_patient_id VARCHAR2(50) := :p_patient_id;
  v_gender VARCHAR2(20) := :p_gender;
  v_cnt NUMBER;
BEGIN
  IF v_str IS NOT NULL THEN
    IF REGEXP_LIKE(v_str, '^\d{4}[-/]\d{2}[-/]\d{2}') THEN
      v_dob := TO_DATE(SUBSTR(v_str, 1, 10), CASE WHEN SUBSTR(v_str, 5, 1) = '/' THEN 'YYYY/MM/DD' ELSE 'YYYY-MM-DD' END);
    ELSIF REGEXP_LIKE(v_str, '^\d{2}[-/]\d{2}[-/]\d{4}') THEN
      v_dob := TO_DATE(SUBSTR(v_str, 1, 10), CASE WHEN SUBSTR(v_str, 3, 1) = '/' THEN 'DD/MM/YYYY' ELSE 'DD-MM-YYYY' END);
    ELSE
      BEGIN
        v_dob := TO_DATE(SUBSTR(v_str, 1, 10), 'YYYY-MM-DD');
      EXCEPTION WHEN OTHERS THEN
        BEGIN
          v_dob := TO_DATE(SUBSTR(v_str, 1, 10), 'DD/MM/YYYY');
        EXCEPTION WHEN OTHERS THEN
          v_dob := NULL;
        END;
      END;
    END IF;
  END IF;

  v_dob := NVL(v_dob, TRUNC(SYSDATE));

  IF v_gender IN ('MALE', 'Nam', 'M') THEN v_gender := 'M';
  ELSIF v_gender IN ('FEMALE', 'Nữ', 'F') THEN v_gender := 'F';
  ELSIF v_gender IS NOT NULL THEN v_gender := 'O';
  END IF;

  -- Validate unique PATIENT_CODE (case-insensitive)
  IF v_patient_id IS NULL OR v_patient_id = '' THEN
    SELECT COUNT(*) INTO v_cnt FROM DEMO_PATIENTS WHERE LOWER(PATIENT_CODE) = LOWER(TRIM(:p_patient_code));
    IF v_cnt > 0 THEN
      raise_application_error(-20001, 'Mã bệnh nhân đã tồn tại trong hệ thống. Vui lòng nhập mã khác!');
    END IF;
  ELSE
    SELECT COUNT(*) INTO v_cnt FROM DEMO_PATIENTS WHERE LOWER(PATIENT_CODE) = LOWER(TRIM(:p_patient_code)) AND PATIENT_ID <> v_patient_id;
    IF v_cnt > 0 THEN
      raise_application_error(-20001, 'Mã bệnh nhân đã tồn tại ở bệnh nhân khác. Vui lòng nhập mã khác!');
    END IF;
  END IF;

  IF v_patient_id IS NULL OR v_patient_id = '' THEN
    SELECT TO_CHAR(DEMO_PATIENTS_SEQ.NEXTVAL) INTO v_patient_id FROM DUAL;
    INSERT INTO DEMO_PATIENTS (
      PATIENT_ID, PATIENT_CODE, FIRST_NAME, LAST_NAME, DATE_OF_BIRTH,
      GENDER, PHONE_NUMBER, EMAIL, ADDRESS, IDENTITY_NUMBER,
      BLOOD_TYPE, ALLERGIES, INSURANCE_NUMBER, INSURANCE_PROVIDER,
      STATUS, CREATED_BY, CREATED_DATE
    ) VALUES (
      v_patient_id, :p_patient_code, :p_first_name, :p_last_name,
      v_dob, v_gender, :p_phone_number, :p_email, :p_address, :p_identity_number,
      :p_blood_type, :p_allergies, :p_insurance_number, :p_insurance_provider,
      NVL(:p_status, 'ACTIVE'), NVL(:p_created_by, USER), SYSDATE
    );
  ELSE
    UPDATE DEMO_PATIENTS
       SET PATIENT_CODE       = :p_patient_code,
           FIRST_NAME         = :p_first_name,
           LAST_NAME          = :p_last_name,
           DATE_OF_BIRTH      = NVL(v_dob, DATE_OF_BIRTH),
           GENDER             = v_gender,
           PHONE_NUMBER       = :p_phone_number,
           EMAIL              = :p_email,
           ADDRESS            = :p_address,
           IDENTITY_NUMBER    = :p_identity_number,
           BLOOD_TYPE         = :p_blood_type,
           ALLERGIES          = :p_allergies,
           INSURANCE_NUMBER   = :p_insurance_number,
           INSURANCE_PROVIDER = :p_insurance_provider
     WHERE PATIENT_ID = v_patient_id;
  END IF;
  :p_patient_id_out := v_patient_id;
END;
